import{_ as a}from"./chunks/001_CleanShot_202026-07-10_20at_2000.14.28_2x_Lxy0b4axOo.Bt0dHdB3.Ljlpp_dt.js";import{_ as d}from"./chunks/001_image_AXyxbhbcqo.C-sVVDrO.DIB4xoLc.js";import{_ as r,o as n,c as s,a0 as o}from"./chunks/framework.jwovEGr5.js";const k=JSON.parse('{"title":"第 3 章 主界面、任务与工作区","description":"","frontmatter":{},"headers":[],"relativePath":"p1/03.md","filePath":"p1/03.md"}'),e={name:"p1/03.md"};function l(i,t,h,p,c,g){return n(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="第-3-章-主界面、任务与工作区" tabindex="-1">第 3 章 主界面、任务与工作区 <a class="header-anchor" href="#第-3-章-主界面、任务与工作区" aria-label="Permalink to &quot;第 3 章 主界面、任务与工作区&quot;">​</a></h1><blockquote><p>本章综合蓝皮书第 3 章与橙皮书「界面布局全解析」「权限模式配置」「模型选择」「工作空间设置」等内容。</p></blockquote><h2 id="界面布局全解析" tabindex="-1">界面布局全解析 <a class="header-anchor" href="#界面布局全解析" aria-label="Permalink to &quot;界面布局全解析&quot;">​</a></h2><p>WorkBuddy 采用经典的三栏布局，和大多数桌面 AI 工作台一致，学会一个，其他基本都会。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────┬──────────────────────────────┬─────────────┐</span></span>
<span class="line"><span>│            │                            │             │</span></span>
<span class="line"><span>│  左侧导航栏  │       主对话区                │   结果面板    │</span></span>
<span class="line"><span>│            │                            │             │</span></span>
<span class="line"><span>│  · 新建任务 │   任务标题栏              │  · Artifacts │</span></span>
<span class="line"><span>│  · 技能    │   消息列表               │  · 所有文件  │</span></span>
<span class="line"><span>│  · 专家    │   输入区                │  · 变更预览  │</span></span>
<span class="line"><span>│  · 连接器   │                            │  · 文件预览  │</span></span>
<span class="line"><span>│  · 自动化   │                            │             │</span></span>
<span class="line"><span>│  · 资料库   │                            │             │</span></span>
<span class="line"><span>│  · 头像设置 │                            │             │</span></span>
<span class="line"><span>└────────────┴──────────────────────────────┴─────────────┘</span></span></code></pre></div><p><strong>📸 WorkBuddy 主界面</strong>（三栏布局：左侧导航 + 中间对话区 + 右侧结果面板）</p><p><img src="`+a+'" alt="WorkBuddy 主界面"></p><h3 id="左侧导航栏" tabindex="-1">左侧导航栏 <a class="header-anchor" href="#左侧导航栏" aria-label="Permalink to &quot;左侧导航栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入口</th><th>功能</th></tr></thead><tbody><tr><td><strong>新建任务</strong></td><td>创建新对话 / 新任务</td></tr><tr><td><strong>技能</strong></td><td>进入 SkillHub，管理已安装和推荐的技能</td></tr><tr><td><strong>专家</strong></td><td>进入专家中心，召唤领域专家或专家团</td></tr><tr><td><strong>连接器</strong></td><td>管理 MCP 连接器（腾讯文档、QQ 邮箱等）</td></tr><tr><td><strong>自动化</strong></td><td>管理定时自动化任务</td></tr><tr><td><strong>资料库</strong></td><td>管理知识库和外部文档来源</td></tr><tr><td><strong>头像</strong></td><td>进入个人设置（模型选择、权限管理、Claw 设置）</td></tr></tbody></table><h3 id="主对话区" tabindex="-1">主对话区 <a class="header-anchor" href="#主对话区" aria-label="Permalink to &quot;主对话区&quot;">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>功能</th></tr></thead><tbody><tr><td><strong>任务标题栏</strong></td><td>显示当前任务名称，支持重命名</td></tr><tr><td><strong>消息列表</strong></td><td>显示 AI 思考过程、执行步骤、输出结果</td></tr><tr><td><strong>输入区</strong></td><td>输入自然语言指令，支持 <code>/技能名</code> 触发 Skill</td></tr></tbody></table><h3 id="结果面板-右侧" tabindex="-1">结果面板（右侧） <a class="header-anchor" href="#结果面板-右侧" aria-label="Permalink to &quot;结果面板（右侧）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>标签页</th><th>功能</th></tr></thead><tbody><tr><td><strong>Artifacts</strong></td><td>显示 AI 生成的可交互内容（图表、网页、PPT）</td></tr><tr><td><strong>所有文件</strong></td><td>本次任务生成和修改的所有文件列表</td></tr><tr><td><strong>变更预览</strong></td><td>显示文件的具体修改内容（diff 视图）</td></tr><tr><td><strong>文件预览</strong></td><td>直接预览生成的文件内容</td></tr></tbody></table><p>💡 结果面板可以通过标题栏的按钮切换显示/隐藏。</p><h2 id="权限模式配置" tabindex="-1">权限模式配置 <a class="header-anchor" href="#权限模式配置" aria-label="Permalink to &quot;权限模式配置&quot;">​</a></h2><p>权限模式决定了 AI <strong>能碰什么、不能碰什么</strong>，是 WorkBuddy 安全机制的核心。</p><h3 id="三种权限模式" tabindex="-1">三种权限模式 <a class="header-anchor" href="#三种权限模式" aria-label="Permalink to &quot;三种权限模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>权限等级</th><th>行为</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>Ask</strong></td><td>最低</td><td>只回答问题，完全不碰文件</td><td>咨询、概念解释、文案起草</td></tr><tr><td><strong>Plan</strong></td><td>中</td><td>先出执行计划，逐条确认后才执行</td><td>多步骤任务、文件处理</td></tr><tr><td><strong>Craft</strong></td><td>最高</td><td>直接操作文件、运行代码，每步仍需你确认</td><td>批量处理、写代码</td></tr></tbody></table><h3 id="如何切换模式" tabindex="-1">如何切换模式 <a class="header-anchor" href="#如何切换模式" aria-label="Permalink to &quot;如何切换模式&quot;">​</a></h3><p>在<strong>输入区上方</strong>可以找到模式切换按钮，点击即可在 Ask / Plan / Craft 之间切换。</p><h3 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h3><p><strong>日常 90% 的任务用 Plan</strong>：先计划后执行，全程可见，随时可以喊停。</p><p><strong>咨询讨论用 Ask</strong>：不需要操作文件，省去不必要的确认步骤。</p><p><strong>批量文件处理和写代码用 Craft</strong>：效率高，但需要盯紧每一步。</p><p>⚠️ <strong>安全提示</strong>：Craft 模式下 AI 可以直接修改文件，建议在处理重要文件前<strong>手动备份</strong>，并开启高危操作二次确认。</p><blockquote><p>💡 <strong>进阶技巧</strong>：可以在记忆（Memory）中写入&quot;任何项目开始时先思考，然后制定计划，最后才执行&quot;的规则，让 Plan 模式成为默认行为。</p></blockquote><p><strong>📸 权限模式切换</strong>（输入区上方可切换 Ask / Plan / Craft 三种模式）</p><p><img src="'+d+'" alt="权限模式切换"></p><h2 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h2><h3 id="配置路径" tabindex="-1">配置路径 <a class="header-anchor" href="#配置路径" aria-label="Permalink to &quot;配置路径&quot;">​</a></h3><p>点击<strong>左下角头像 → 设置 → 模型选项</strong>，即可切换模型。</p><h3 id="模型选择对照表" tabindex="-1">模型选择对照表 <a class="header-anchor" href="#模型选择对照表" aria-label="Permalink to &quot;模型选择对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>优势场景</th><th>响应速度</th><th>中文能力</th><th>推荐场景</th></tr></thead><tbody><tr><td><strong>混元</strong></td><td>日常办公、快速任务</td><td>⚡⚡⚡⚡⚡</td><td>★★★★★</td><td>日常办公（首选）</td></tr><tr><td><strong>DeepSeek</strong></td><td>复杂推理、逻辑分析</td><td>⚡⚡⚡</td><td>★★★★☆</td><td>深度分析、代码推理</td></tr><tr><td><strong>GLM</strong></td><td>代码任务、技术文档</td><td>⚡⚡⚡</td><td>★★★★☆</td><td>代码生成、技术写作</td></tr><tr><td><strong>Kimi</strong></td><td>创意写作、长文本</td><td>⚡⚡⚡</td><td>★★★★★</td><td>公众号文章、长文创作</td></tr><tr><td><strong>MiniMax</strong></td><td>多模态、图像理解</td><td>⚡⚡⚡</td><td>★★★☆☆</td><td>图文混合任务</td></tr></tbody></table><h3 id="场景推荐" tabindex="-1">场景推荐 <a class="header-anchor" href="#场景推荐" aria-label="Permalink to &quot;场景推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th>使用场景</th><th>推荐模型</th><th>理由</th></tr></thead><tbody><tr><td>日常办公</td><td>混元</td><td>响应快、中文优化好、省积分</td></tr><tr><td>复杂推理</td><td>DeepSeek</td><td>推理能力强</td></tr><tr><td>代码任务</td><td>GLM / Kimi</td><td>代码理解能力突出</td></tr><tr><td>创意写作</td><td>Kimi</td><td>文本生成质量高</td></tr><tr><td>自动化定时任务（轻量）</td><td>混元 / MiniMax</td><td>省积分</td></tr></tbody></table><p>💡 <strong>省积分技巧</strong>：轻量任务（消息提炼、格式转换）用轻量模型；重度任务（代码分析、长报告）用 reasoning 模型，但频率降低到 WEEKLY。</p><h2 id="工作空间设置" tabindex="-1">工作空间设置 <a class="header-anchor" href="#工作空间设置" aria-label="Permalink to &quot;工作空间设置&quot;">​</a></h2><h3 id="修改默认存储路径" tabindex="-1">修改默认存储路径 <a class="header-anchor" href="#修改默认存储路径" aria-label="Permalink to &quot;修改默认存储路径&quot;">​</a></h3><p><strong>默认路径在 C 盘，长期使用会爆满！</strong> 务必修改：</p><ol><li>点击<strong>左下角头像 → 设置</strong></li><li>选择<strong>系统设置</strong></li><li>找到<strong>工作空间存储路径</strong></li><li>修改为非系统盘的路径（如 <code>D:\\WorkBuddy-Workspace</code> 或 <code>/Users/xxx/WorkBuddy-Workspace</code>）</li></ol><h3 id="工作空间与自动化" tabindex="-1">工作空间与自动化 <a class="header-anchor" href="#工作空间与自动化" aria-label="Permalink to &quot;工作空间与自动化&quot;">​</a></h3><p>创建自动化任务时，可以指定专属工作空间：</p><ul><li>默认自动分配 <code>automation-claw-xxxx</code> 命名的工作空间</li><li>用于存放任务执行过程和结果文件，避免文件混乱</li><li>建议为不同自动化任务设置不同的工作目录</li></ul><hr><p><em>（你可以在本章后面插入 <code>![](/assets/your-screenshot.png)</code> 来添加你自己的截图。）</em></p>',45)])])}const q=r(e,[["render",l]]);export{k as __pageData,q as default};
